const AgentChatModal = ({ agent, onClose }) => {
  const [isDark, setIsDark]     = useState(true);
  const [messages, setMessages] = useState([]);
  const [input, setInput]       = useState('');
  const [loading, setLoading]   = useState(false);
  const [stream, setStream]     = useState('');
  const endRef = useRef(null);

  useEffect(() => {
    const saved = localStorage.getItem('nexusai_theme');
    setIsDark(saved !== 'light');
  }, []);

  useEffect(() => { endRef.current?.scrollIntoView({ behavior:'smooth' }); }, [messages, stream]);

  const send = async (text) => {
    const msg = text || input;
    if (!msg.trim() || loading) return;
    setInput('');
    setMessages(prev => [...prev, { role:'user', content:msg }]);
    setLoading(true); setStream('');
    await new Promise(r => setTimeout(r, 800));
    const reply = `✨ **${agent.name}**\n\nI've analyzed your request:\n"${msg.slice(0,80)}..."\n\n${agent.description}\n\nHow else may I assist you today? 💫`;
    const words = reply.split(' ');
    for (let i = 0; i <= words.length; i++) {
      await new Promise(r => setTimeout(r, 15));
      setStream(words.slice(0,i).join(' '));
    }
    setMessages(prev => [...prev, { role:'agent', content:reply }]);
    setStream(''); setLoading(false);
  };

  const glass = isDark ? 'rgba(13,13,20,0.95)' : 'rgba(255,255,255,0.95)';
  const border = isDark ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.08)';

