        <div style={{ width:48,height:48,borderRadius:14,background:`${agent.color}20`,border:`1px solid ${agent.color}40`,display:'flex',alignItems:'center',justifyContent:'center',fontSize:24,boxShadow:`0 0 20px ${agent.color}30` }}>{agent.icon}</div>
        <div style={{ flex:1 }}>
          <div style={{ fontWeight:800,fontSize:16,background:`linear-gradient(135deg,#fff,${agent.color})`,color: isDark ? 'white' : 'black',WebkitTextFillColor:'transparent' }}>{agent.name}</div>
          <div style={{ fontSize:12,color:isDark?'rgba(255,255,255,0.45)':'rgba(0,0,0,0.45)',marginTop:2 }}>{agent.tagline}</div>
        </div>
        <div style={{ display:'flex',alignItems:'center',gap:8,padding:'6px 14px',background:`${agent.color}15`,border:`1px solid ${agent.color}30`,borderRadius:40 }}>
          <div style={{ width:7,height:7,borderRadius:'50%',background:'#10B981',boxShadow:'0 0 8px #10B981',animation:'pulse 2s infinite' }} />
          <span style={{ fontSize:12,color:agent.color,fontWeight:600 }}>ONLINE</span>
        </div>
      </div>

      {/* Messages */}
      <div style={{ flex:1,overflowY:'auto',padding:'28px 32px',scrollbarWidth:'thin',scrollbarColor:`${agent.color}30 transparent` }}>
