          <div style={{ textAlign:'center',padding:'60px 20px' }}>
            <div style={{ width:100,height:100,borderRadius:28,background:`${agent.color}15`,border:`2px solid ${agent.color}30`,display:'flex',alignItems:'center',justifyContent:'center',fontSize:52,margin:'0 auto 24px',boxShadow:`0 0 40px ${agent.color}20` }}>{agent.icon}</div>
