                <button key={i} onClick={() => send(p)} style={{ padding:'12px 16px',background:`${agent.color}10`,border:`1px solid ${agent.color}25`,borderRadius:14,cursor:'pointer',color:isDark?'rgba(255,255,255,0.8)':'rgba(0,0,0,0.8)',fontSize:13,textAlign:'left',transition:'all 0.2s',fontFamily:'inherit' }}>{p}</button>
              ))}
            </div>
