        @keyframes pulse {
          0%,100% { opacity: 1; transform: scale(1); }
          50%     { opacity: 0.5; transform: scale(0.85); }
        }
        @keyframes ripple {
          0%   { transform: translate(-50%,-50%) scale(1); opacity: 0.6; }
          100% { transform: translate(-50%,-50%) scale(2.8); opacity: 0; }
        }
        @keyframes signalPulse {
          0%   { opacity: 0.4; }
          100% { opacity: 1; }
        }
        @keyframes neuronPulse {
          0%,100% { r: 4; opacity: 0.4; }
          50%     { r: 6; opacity: 0.9; }
        }
        @keyframes barPulse {
          0%   { transform: scaleY(0.6); }
          100% { transform: scaleY(1); }
        }
        @keyframes gridMove {
          0%   { background-position: 0 0; }
          100% { background-position: 60px 60px; }
        }
        @keyframes borderGlow {
          0%,100% { box-shadow: 0 0 0 0 rgba(168,85,247,0); }
          50%     { box-shadow: 0 0 20px 4px rgba(168,85,247,0.3); }
        }

        /* ── Stat cards ── */
        .stat-card-premium { transition: all 0.35s cubic-bezier(0.2,0.9,0.4,1.1) !important; }
        .stat-card-premium:hover {
          transform: translateY(-8px) scale(1.02) !important;
          box-shadow: 0 20px 50px rgba(0,0,0,0.3), 0 0 30px rgba(168,85,247,0.15) !important;
        }

        /* ── Agent cards ── */
        .agent-card-premium { transition: all 0.35s cubic-bezier(0.2,0.9,0.4,1.2); }

        /* ── Activity ── */
        .activity-item:hover { transform: translateX(6px); }

        /* ── Insight cards ── */
        .insight-card:hover {
          transform: translateY(-6px);
          box-shadow: 0 16px 40px rgba(0,0,0,0.2) !important;
        }

        /* ── Quick action buttons ── */
        .quick-action-btn:hover {
          transform: translateY(-6px) scale(1.04) !important;
          border-color: rgba(168,85,247,0.5) !important;
          box-shadow: 0 16px 40px rgba(0,0,0,0.2) !important;
        }
        .quick-action-btn:hover .action-glow { opacity: 1 !important; }
        .quick-action-btn:hover .action-line { transform: scaleX(1) !important; }

        /* ── Node cards ── */
        .node-card:hover {
          transform: translateY(-3px);
          box-shadow: 0 8px 20px rgba(0,0,0,0.15);
        }

        /* ── Efficiency cards ── */
        .efficiency-card:hover {
          transform: translateY(-6px);
          box-shadow: 0 14px 40px rgba(0,0,0,0.18) !important;
        }

        /* ── Footer links ── */
        .footer-link:hover { color: rgba(168,85,247,0.8); }

        /* ── Scrollbar ── */
        ::-webkit-scrollbar { width: 6px; height: 6px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: rgba(168,85,247,0.3); border-radius: 3px; }
        ::-webkit-scrollbar-thumb:hover { background: rgba(168,85,247,0.6); }

        /* ── Responsive ── */
        @media (max-width: 1024px) {
          div[style*="grid-template-columns: 1fr 1fr"] {
            grid-template-columns: 1fr !important;
          }
        }
        @media (max-width: 768px) {
          nav { padding: 12px 20px !important; }
          nav span:not(:first-child) { display: none; }
          .stat-card-premium { min-width: 0; }
          div[style*="padding: 48px 48px"] { padding: 28px 24px !important; }
          div[style*="maxWidth: 1440px"] { padding: 24px 16px !important; }
          h1[style*="clamp(32px"] { font-size: clamp(24px,6vw,36px) !important; }
          div[style*="grid-template-columns: 1fr auto"] {
            grid-template-columns: 1fr !important;
          }
        }
        @media (max-width: 480px) {
          div[style*="repeat(3, 1fr)"] { grid-template-columns: 1fr !important; }
          div[style*="repeat(4, 1fr)"] { grid-template-columns: repeat(2,1fr) !important; }
        }
      `}</style>
    </div>
  );
};

export default DashboardPage;
